	/**
	 * Resets the board to the starting position (before any moves).
	 *
	 * Also restores initial clock times if clock history data is available.
	 */
	start() {
		this.chess.reset();
		this.currentMoveIndex.set(-1);
		this.currentFen.set(this.chess.fen());

		if (this.clockHistory.length > 0) {
			const startClocks = this.clockHistory[0];
			if (startClocks) {
				this.whiteTimeRemaining.set(this.formatTime(startClocks.white));
				this.blackTimeRemaining.set(this.formatTime(startClocks.black));
			}
		}
	}

	/**
	 * Jumps to the final position of the current game.
	 *
	 * Replays all moves from the start to reach the end-of-game position.
	 */
	end() {
		this.chess.reset();
		const moves = this.moves();
		for (const move of moves) {
			this.chess.move(move);
		}
		this.currentMoveIndex.set(moves.length - 1);
		this.currentFen.set(this.chess.fen());
	}

	// --- Replay Logic ---

	/**
	 * Starts an auto-replay of the current game from the beginning.
	 *
	 * Stops any in-progress replay, resets to the start position,
	 * then runs the replay logic with timing based on the selected mode.
	 */
	replayGame() {
		this.stopReplay();
		this.start();
		this.runReplayLogic();
	}

	/**
	 * Continues an auto-replay from the current move position.
	 *
	 * Preserves the replay Promise (doesn't resolve it prematurely)
	 * so batch replay sequences can resume from where they left off.
	 */
	continueReplay() {
		this.stopReplay(false);
		this.runReplayLogic();
	}

	/**
	 * Executes the replay logic for the currently loaded game.
	 *
	 * Parses the game PGN, calculates move timing based on the selected
	 * {@link replayMode}, and schedules the replay via {@link scheduleReplay}.
	 */
	private runReplayLogic() {
		// Use the currently loaded PGN from the input area
		const gamePgn = this.pgnInput();
		const onComplete = this.replayResolve
			? () => {
					if (this.replayResolve) {
						this.replayResolve();
						this.replayResolve = null;
					}
				}
			: undefined;

		try {
			const tempChess = new Chess();
			tempChess.loadPgn(gamePgn);
			const history = tempChess.history({ verbose: true });

			const timeOuts = this.calculateReplayTimeouts(history);
			this.scheduleReplay(timeOuts, history.length, onComplete);
		} catch (_e) {
			// console.warn("Replay PGN parsing failed with chess.js, trying chessops", e);
			try {
				const timeOuts = this.calculateReplayTimeoutsChessops(gamePgn);
				this.scheduleReplay(timeOuts, timeOuts.length, onComplete);
			} catch (_e2) {
				// console.warn("Replay PGN parsing failed with chessops, falling back to simple replay", e2);
				// Fallback: use moves list length and fixed time
				const moveCount = this.moves().length;
				const timeOuts = Array(moveCount)
					.fill(0)
					.map((_, i) => (i + 1) * this.fixedTime());
				this.scheduleReplay(timeOuts, moveCount);
			}
		}
	}

	/**
	 * Sequentially replays all selected games in the filtered game list.
	 *
	 * Each game is loaded, replayed from start to finish, then a 2-second pause
	 * is inserted before the next game. Respects the current filter sort order.
	 */
	async replayAllSelectedGames() {
		this.stopReplay();
		this.isReplayingSequence = true;

		// Use filteredGamesIndices to maintain the sort order (by Elo sum)
		// Filter this list to include only selected games
		const selectedSet = this.selectedGames();
		const selected = this.filteredGamesIndices().filter((idx) =>
			selectedSet.has(idx),
		);

		if (selected.length === 0) {
			this.showMessage('No games selected. Please select games to replay.');
			return;
		}

		for (let i = 0; i < selected.length; i++) {
			if (!this.isReplayingSequence) break;
			const gameIndex = selected[i];
			this.loadGame(gameIndex);

			// Wait for the game to load
			await new Promise((resolve) => setTimeout(resolve, 100));

			// Replay the current game
			await this.replayGameAsync();

			// Wait a bit between games (2 seconds)
			if (i < selected.length - 1) {
				await new Promise((resolve) => setTimeout(resolve, 2000));
			}
		}
	}

	/**
	 * Returns a Promise that resolves when the current game's replay completes.
	 *
	 * Used by batch replay sequences to await each game's auto-play before
	 * moving to the next selected game.
	 *
	 * @returns Promise resolved by {@link scheduleReplay} via {@link replayResolve}.
	 */
	private replayGameAsync(): Promise<void> {
		return new Promise((resolve) => {
			this.stopReplay();
			this.replayResolve = resolve;
			this.start();

			const gamePgn = this.pgnInput();

			try {
				const tempChess = new Chess();
				tempChess.loadPgn(gamePgn);
				const history = tempChess.history({ verbose: true });

				const timeOuts = this.calculateReplayTimeouts(history);

				// Actually schedule the replay
				this.scheduleReplay(timeOuts, history.length, () => {
					resolve();
					this.replayResolve = null;
				});
			} catch (_e) {
				// console.warn("Replay PGN parsing failed with chess.js, trying chessops", e);
				try {
					const timeOuts = this.calculateReplayTimeoutsChessops(gamePgn);
					this.scheduleReplay(timeOuts, timeOuts.length, () => {
						resolve();
						this.replayResolve = null;
					});
				} catch (_e2) {
					// console.warn("Replay PGN parsing failed with chessops, falling back to simple replay", e2);
					// Fallback
					const moveCount = this.moves().length;
					const timeOuts = Array(moveCount)
						.fill(0)
						.map((_, i) => (i + 1) * this.fixedTime());

					this.scheduleReplay(timeOuts, moveCount, () => {
						resolve();
						this.replayResolve = null;
					});
				}
			}
		});
	}

	/**
	 * Stops any in-progress replay, clears scheduled timeouts, and optionally
	 * resolves the replay Promise used by batch replay sequences.
	 *
	 * @param resolvePromise — When `true` (default), resolve any pending replay Promise.
	 */
	stopReplay(resolvePromise = true) {
		this.isReplaying.set(false);
		this.replayTimeouts.forEach((t) => {
			clearTimeout(t);
			this.pendingTimeouts.delete(t);
		});
		this.replayTimeouts = [];

		if (resolvePromise && this.replayResolve) {
			this.replayResolve();
			this.replayResolve = null;
		}
	}

	/**
	 * Calculates replay timeouts by parsing clock comments from the PGN via chessops.
	 *
	 * Fallback used when chess.js parsing fails. Reads `[%clk h:m:s]` comments
	 * to determine think time per move in `'realtime'` and `'proportional'` modes.
	 *
	 * @param pgn — Raw PGN string for the game.
	 * @returns Array of seconds delays, one per move.
	 */
	private calculateReplayTimeoutsChessops(pgn: string): number[] {
		const games = parsePgn(pgn);
		if (games.length === 0) throw new Error('No games found by chessops');

		const game = games[0];
		const timeOuts: number[] = [];
		this.clockHistory = [];

		// Try to parse time control from headers
		let timeControlSeconds = 0;
		if (game.headers.has('TimeControl')) {
			const tc = game.headers.get('TimeControl')?.split('+');
			if (tc) timeControlSeconds = parseInt(tc[0], 10);
		}

		let whiteTime = timeControlSeconds;
		let blackTime = timeControlSeconds;
		this.clockHistory.push({ white: whiteTime, black: blackTime });

		const thinkTimes: number[] = [];
		let node = game.moves;
		let isWhite = true;

		while (node.children.length > 0) {
			const child = node.children[0]; // Main line
			let moveTime = 0;
			let hasClockComment = false;

			// Check comments for clock
			if (child.data?.comments) {
				for (const comment of child.data.comments) {
					const clkMatch = comment.match(/%clk\s+(?:(\d+):)?(\d+):(\d+)/);
					if (clkMatch) {
						hasClockComment = true;
						let h = 0,
							m = 0,
							s = 0;
						if (clkMatch[1]) h = parseInt(clkMatch[1], 10);
						m = parseInt(clkMatch[2], 10);
						s = parseInt(clkMatch[3], 10);

						const timeInSeconds = h * 3600 + m * 60 + s;

						if (isWhite) {
							moveTime = Math.max(0.1, whiteTime - timeInSeconds);
							whiteTime = timeInSeconds;
						} else {
							moveTime = Math.max(0.1, blackTime - timeInSeconds);
							blackTime = timeInSeconds;
						}
						break; // Found clock, stop looking
					}
				}
			}

			if (!hasClockComment) {
				moveTime = this.fixedTime();
			}

			thinkTimes.push(moveTime);
			this.clockHistory.push({ white: whiteTime, black: blackTime });

			node = child;
			isWhite = !isWhite;
		}

		// Calculate timeouts based on mode (reuse logic if possible, or duplicate for now)
		if (this.replayMode() === 'fixed') {
			return thinkTimes.map((_, i) => (i + 1) * this.fixedTime());
		}

		if (this.replayMode() === 'realtime') {
			let totalTime = 0;
			for (let i = 0; i < thinkTimes.length; i++) {
				totalTime += thinkTimes[i];
				timeOuts.push(totalTime);
			}
			return timeOuts;
		}

		if (this.replayMode() === 'proportional') {
			const totalGameDuration = thinkTimes.reduce((a, b) => a + b, 0);
			const targetDurationSeconds = this.proportionalDuration() * 60;
			const scaleFactor =
				totalGameDuration > 0 ? targetDurationSeconds / totalGameDuration : 1;
			const minSeconds = this.minSecondsBetweenMoves();

			let currentScaledTime = 0;
			for (let i = 0; i < thinkTimes.length; i++) {
				let scaledMoveTime = thinkTimes[i] * scaleFactor;
				if (scaledMoveTime < minSeconds) {
					scaledMoveTime = minSeconds;
				}
				currentScaledTime += scaledMoveTime;
				timeOuts.push(currentScaledTime);
			}
			return timeOuts;
		}

		return thinkTimes.map((_, i) => (i + 1) * 1);
	}

	/**
	 * Clock state at each half-move: remaining seconds for white and black.
	 * Index 0 is the initial clock state. Populated by {@link calculateReplayTimeouts}.
	 */
	private clockHistory: { white: number; black: number }[] = [];

	/**
	 * Calculates per-move replay delays from game history and clock comments.
	 *
	 * Parses `[%clk h:m:s]` comments to compute think times. Supports three modes:
	 * `'fixed'` (constant delay), `'realtime'` (actual think time), and
	 * `'proportional'` (scaled to fit {@link proportionalDuration}).
	 *
	 * @param history — Verbose move history from chess.js.
	 * @returns Array of seconds delays, one per move.
	 */
	private calculateReplayTimeouts(history: Move[]): number[] {
		const timeOuts: number[] = [];
		this.clockHistory = [];

		// Get comments and header to parse clocks
		const comments = this.chess.getComments();
		const header = this.chess.header();

		// Try to parse time control
		let timeControlSeconds = 0;
		if (header.TimeControl) {
			const tc = header.TimeControl.split('+');
			timeControlSeconds = parseInt(tc[0], 10);
		}

		// Initialize clocks
		let whiteTime = timeControlSeconds;
		let blackTime = timeControlSeconds;

		// If we have clock comments, use them as source of truth
		// Check first few moves for clock comments
		let hasClockComments = false;
		for (let i = 0; i < Math.min(history.length, 10); i++) {
			const _comment = comments.find(
				(c) => c.fen === history[i].after || c.fen === history[i].before,
			); // Approximate check
			// Actually chess.js getComments returns array of objects with fen and comment.
			// We need to match moves to comments.
			// A simpler way is to iterate moves and get comments for the position.
		}

		// Re-simulate game to extract clocks correctly
		const tempChess = new Chess();
		// Use the raw PGN input to ensure we have comments
		tempChess.loadPgn(this.pgnInput());
		const moves = tempChess.history({ verbose: true });
		const moveComments = tempChess.getComments();

		// Map FEN to comment for easier lookup
		const fenToComment = new Map<string, string>();
		moveComments.forEach((c) => {
			fenToComment.set(c.fen, c.comment);
		});

		// Initial clock state
		this.clockHistory.push({ white: whiteTime, black: blackTime });

		// Calculate think times
		const thinkTimes: number[] = [];

		for (let i = 0; i < moves.length; i++) {
			const move = moves[i];
			const isWhite = move.color === 'w';
			// chess.js attaches comments to the position AFTER the move
			const comment = fenToComment.get(move.after);

			let moveTime = 0;

			if (comment) {
				// Try to parse %clk
				// Matches: [%clk 0:03:02] or [%clk 03:02] or [%clk 3:02]
				const clkMatch = comment.match(/%clk\s+(?:(\d+):)?(\d+):(\d+)/);
				if (clkMatch) {
					hasClockComments = true;
					let h = 0,
						m = 0,
						s = 0;

					if (clkMatch[1]) {
						h = parseInt(clkMatch[1], 10);
					}
					m = parseInt(clkMatch[2], 10);
					s = parseInt(clkMatch[3], 10);

					const timeInSeconds = h * 3600 + m * 60 + s;

					if (isWhite) {
						moveTime = Math.max(0.1, whiteTime - timeInSeconds);
						whiteTime = timeInSeconds;
					} else {
						moveTime = Math.max(0.1, blackTime - timeInSeconds);
						blackTime = timeInSeconds;
					}
				}
			}

			// Fallback if no clock comment or parsing failed
			if (moveTime === 0 && !hasClockComments) {
				moveTime = this.fixedTime(); // Default to fixed time setting
			} else if (moveTime === 0 && hasClockComments) {
				// If we have clock comments generally but missed this one, assume small time
				moveTime = 1;
			}

			thinkTimes.push(moveTime);
			this.clockHistory.push({ white: whiteTime, black: blackTime });
		}

		// If no clock comments found at all, clear clock history so we don't show empty clocks
		if (!hasClockComments) {
			this.clockHistory = [];
			this.whiteTimeRemaining.set('');
			this.blackTimeRemaining.set('');
		} else {
			// Set initial clocks for display
			if (this.clockHistory.length > 0) {
				this.whiteTimeRemaining.set(
					this.formatTime(this.clockHistory[0].white),
				);
				this.blackTimeRemaining.set(
					this.formatTime(this.clockHistory[0].black),
				);
			}
		}

		if (this.replayMode() === 'fixed') {
			for (let i = 0; i < history.length; i++) {
				timeOuts.push((i + 1) * this.fixedTime());
			}
			return timeOuts;
		}

		if (this.replayMode() === 'realtime') {
			let totalTime = 0;
			for (let i = 0; i < thinkTimes.length; i++) {
				totalTime += thinkTimes[i];
				timeOuts.push(totalTime);
			}
			return timeOuts;
		}

		if (this.replayMode() === 'proportional') {
			// Calculate total game duration
			const totalGameDuration = thinkTimes.reduce((a, b) => a + b, 0);
			const targetDurationSeconds = this.proportionalDuration() * 60;
			const scaleFactor =
				totalGameDuration > 0 ? targetDurationSeconds / totalGameDuration : 1;
			const minSeconds = this.minSecondsBetweenMoves();

			let currentScaledTime = 0;
			for (let i = 0; i < thinkTimes.length; i++) {
				let scaledMoveTime = thinkTimes[i] * scaleFactor;
				if (scaledMoveTime < minSeconds) {
					scaledMoveTime = minSeconds;
				}
				currentScaledTime += scaledMoveTime;
				timeOuts.push(currentScaledTime);
			}
			return timeOuts;
		}

		// Fallback
		for (let i = 0; i < history.length; i++) {
			timeOuts.push((i + 1) * 1);
		}

		return timeOuts;
	}

	/**
	 * Formats a duration in seconds as a clock display string.
	 *
	 * @param seconds — Duration in seconds.
	 * @returns Formatted string: `"h:mm:ss"` or `"m:ss"`.
	 */
	private formatTime(seconds: number): string {
		const h = Math.floor(seconds / 3600);
		const m = Math.floor((seconds % 3600) / 60);
		const s = Math.floor(seconds % 60);

		if (h > 0) {
			return `${h}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')} `;
		}
		return `${m}:${s.toString().padStart(2, '0')} `;
	}

	/**
	 * Parses a `[%eval ...]` PGN comment value into a numeric score.
	 *
	 * Mate scores (`#3`, `#-2`) are converted to large values near ±20.
	 * Centipawn scores are parsed as floats.
	 *
	 * @param evalStr — Raw evaluation string, or `null`.
	 * @returns Numeric evaluation score, or `null` if unparseable.
	 */
	private parseEval(evalStr: string | null): number | null {
		if (!evalStr) return null;
		if (evalStr.startsWith('#')) {
			const val = parseInt(evalStr.substring(1), 10);
			return val > 0 ? 20 + 10 / Math.abs(val) : -(20 + 10 / Math.abs(val));
		}
		return parseFloat(evalStr);
	}

	/**
	 * Schedules timed callbacks to auto-play moves during replay.
	 *
	 * Uses the selected replay mode timing, handles the "stop on error" feature
	 * (pauses when evaluation change exceeds {@link stopOnErrorThreshold}),
	 * and calls the optional `onComplete` callback after the last move.
	 *
	 * @param timeOuts — Per-move delays in seconds.
	 * @param totalMoves — Total number of moves in the game.
	 * @param onComplete — Optional callback when replay finishes.
	 */
	private scheduleReplay(
		timeOuts: number[],
		totalMoves: number,
		onComplete?: () => void,
	) {
		const _totalGameTime = timeOuts[timeOuts.length - 1] || 1;
		this.isReplaying.set(true);
		this.showBetterMoveBtn.set(false);
		this.analysisVisible.set(false);
		this.bestMoveInfo.set(null);

		const startMoveIndex = this.currentMoveIndex() + 1; // Start from next move

		if (startMoveIndex >= totalMoves) {
			this.isReplaying.set(false);
			if (onComplete) onComplete();
			return;
		}

		const startTime = startMoveIndex > 0 ? timeOuts[startMoveIndex - 1] : 0;

		for (let i = startMoveIndex; i < totalMoves; i++) {
			let delay = 0;
			if (
				this.replayMode() === 'fixed' ||
				this.replayMode() === 'realtime' ||
				this.replayMode() === 'proportional'
			) {
				// Calculate relative delay from "now" (which corresponds to startTime in the game)
				delay = (timeOuts[i] - startTime) * 1000;
			} else {
				// Fallback
				delay = (i - startMoveIndex + 1) * 1000;
			}

			// Ensure non-negative delay
			delay = Math.max(0, delay);

			const isLast = i === totalMoves - 1;
			const timeoutId = setTimeout(() => {
				this.next();

				// Stop on Error Check
				if (this.stopOnError()) {
					const currentIdx = this.currentMoveIndex();
					const evals = this.evaluations();
					if (currentIdx > 0 && currentIdx < evals.length) {
						const currentEval = this.parseEval(evals[currentIdx]);
						const prevEval = this.parseEval(evals[currentIdx - 1]);

						if (currentEval !== null && prevEval !== null) {
							// If diff > threshold
							if (
								Math.abs(currentEval - prevEval) > this.stopOnErrorThreshold()
							) {
								this.stopReplay(false);

								const prevFen = this.getFenBeforeMove(currentIdx);
								if (prevFen) {
									this.showBetterMoveBtn.set(true);
									this.analyzePosition(prevFen);
								}
							}
						}
					}
				}

				if (isLast && onComplete && this.isReplaying()) {
					// Give a small buffer for the last animation
					const completionTimeoutId = this.setDeferredTimeout(() => {
						// Only call onComplete if we didn't stop manually (check isReplaying?)
						// stopReplay() sets isReplaying to false.
						// If we stopped on error, we don't proceed to next game in sequence.
						if (onComplete) onComplete();
					}, 500);
					this.replayTimeouts.push(completionTimeoutId);
				}
			}, delay);
			this.replayTimeouts.push(timeoutId);
		}
	}

	/**
	 * Returns the FEN string representing the position before a given move.
	 *
	 * Used by the "stop on error" feature to determine the position where
	 * a large evaluation swing occurred.
	 *
	 * @param moveIndex — The 0-based move index. Returns the FEN before this move.
	 * @returns FEN string, or `null` on error.
	 */
	private getFenBeforeMove(moveIndex: number): string | null {
		try {
			const tempChess = new Chess();
			tempChess.loadPgn(this.pgnInput());
			// Navigate to moveIndex - 1
			// history returns array of moves.
			const moves = tempChess.history();
			tempChess.reset();
			for (let i = 0; i < moveIndex; i++) {
				tempChess.move(moves[i]);
			}
			return tempChess.fen();
		} catch (e) {
			console.error('Error generating previous FEN', e);
			return null;
		}
	}
}

styleUrlsData.data:
/* ==========================================================================
   NGX Chessground — PGN Viewer
   Design System: Data-Dense Dashboard
   ========================================================================== */

/* ---- Custom Properties (fallbacks for library context) ---- */
:host {
  --cg-primary: #0F172A;
  --cg-primary-hover: #1E293B;
  --cg-primary-light: #E2E8F0;
  --cg-secondary: #334155;
  --cg-accent: #0369A1;
  --cg-accent-hover: #0284C7;
  --cg-cta: #0369A1;
  --cg-cta-hover: #0284C7;
  --cg-danger: #DC2626;
  --cg-danger-hover: #B91C1C;
  --cg-bg-page: #F8FAFC;
  --cg-bg-surface: #ffffff;
  --cg-bg-alt: #F1F5F9;
  --cg-bg-hover: #E2E8F0;
  --cg-text: #0F172A;
  --cg-text-secondary: #475569;
  --cg-text-muted: #94A3B8;
  --cg-text-inverse: #ffffff;
  --cg-border: #CBD5E1;
  --cg-border-light: #E2E8F0;
  --cg-radius-sm: 4px;
  --cg-radius-md: 8px;
  --cg-radius-lg: 12px;
  --cg-radius-xl: 16px;
  --cg-radius-full: 9999px;
  --cg-shadow-sm: 0 1px 2px rgba(15, 23, 42, 0.04);
  --cg-shadow-md: 0 4px 6px rgba(15, 23, 42, 0.06);
  --cg-shadow-lg: 0 10px 25px rgba(15, 23, 42, 0.08);
  --cg-transition: 200ms ease;
  --cg-font-heading: "Fira Sans", system-ui, sans-serif;
  --cg-font-body: "Fira Sans", system-ui, sans-serif;
  --cg-font-mono: "Fira Code", "JetBrains Mono", "Courier New", monospace;

  display: flex;
  flex-direction: column;
  height: 100%;
  min-height: 0;
  width: 100%;
}

/* ---- Dark Theme Overrides ---- */
:host-context(html[data-theme="dark"]) {
  --cg-primary: #E2E8F0;
  --cg-primary-hover: #CBD5E1;
  --cg-primary-light: #1E293B;
  --cg-secondary: #94A3B8;
  --cg-accent: #38BDF8;
  --cg-accent-hover: #7DD3FC;
  --cg-cta: #38BDF8;
  --cg-cta-hover: #7DD3FC;
  --cg-danger: #F87171;
  --cg-danger-hover: #FCA5A5;
  --cg-bg-page: #0F172A;
  --cg-bg-surface: #1E293B;
  --cg-bg-alt: #334155;
  --cg-bg-hover: #334155;
  --cg-text: #F1F5F9;
  --cg-text-secondary: #94A3B8;
  --cg-text-muted: #64748B;
  --cg-text-inverse: #0F172A;
  --cg-border: #334155;
  --cg-border-light: #1E293B;
  --cg-shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.3);
  --cg-shadow-md: 0 4px 6px rgba(0, 0, 0, 0.4);
  --cg-shadow-lg: 0 10px 25px rgba(0, 0, 0, 0.5);
}

/* ---- Layout ---- */
.pgn-viewer-container {
  display: flex;
  flex-direction: column;
  flex: 1;
  min-height: 0;
  width: 100%;
  background-color: var(--cg-bg-page);
  font-family: var(--cg-font-body);
  overflow: hidden;
}

.main-content {
  display: flex;
  flex: 1;
  min-height: 0;
  overflow: hidden;
}

/* ---- Panels ---- */
.panel {
  display: flex;
  flex-direction: column;
  padding: var(--cg-pad, 0.75rem);
  background-color: var(--cg-bg-surface);
  overflow-y: auto;
  gap: 0.75rem;
}

.panel h3 {
  font-family: var(--cg-font-heading);
  font-size: 0.75rem;
  font-weight: 600;
  color: var(--cg-text);
  margin: 0;
  padding-bottom: 0.35rem;
  border-bottom: 2px solid var(--cg-accent);
  letter-spacing: 0.02em;
  text-transform: uppercase;
}

.left-panel {
  width: var(--cg-panel-w, 300px);
  min-width: var(--cg-panel-min, 260px);
  border-right: 1px solid var(--cg-border);
  gap: 0.5rem;
}

.center-panel {
  flex: 1;
  background-color: var(--cg-bg-page);
  align-items: center;
  justify-content: flex-start;
  gap: 1rem;
  padding: 1rem;
  overflow-y: auto;
}

.right-panel {
  width: var(--cg-panel-w, 300px);
  min-width: var(--cg-panel-min, 260px);
  border-left: 1px solid var(--cg-border);
  gap: 0.5rem;
}

/* ---- Responsive ---- */
@media (max-width: 850px) {
  .main-content {
    flex-direction: column;
    overflow-y: auto;
  }

  .left-panel,
  .right-panel {
    width: 100%;
    min-width: 100%;
    border: none;
  }

  .left-panel {
    border-bottom: 1px solid var(--cg-border);
  }

  .right-panel {
    border-top: 1px solid var(--cg-border);
  }

  .center-panel {
    gap: 0.75rem;
    padding: 0.75rem;
  }
}

/* ---- Filter Section ---- */
.filter-section {
  display: flex;
  flex-direction: column;
  gap: 0.45rem;
  padding-bottom: 0.5rem;
  border-bottom: 1px solid var(--cg-border-light);
}

.filter-row {
  display: flex;
  gap: 0.35rem;
}

.filter-row input[type="text"],
.filter-row select {
  flex: 1;
  padding: 0.35rem 0.5rem;
  border: 1px solid var(--cg-border);
  border-radius: var(--cg-radius-sm);
  font-size: 0.8rem;
  font-family: var(--cg-font-body);
  background: var(--cg-bg-surface);
  color: var(--cg-text);
  cursor: pointer;
  transition: border-color var(--cg-transition), box-shadow var(--cg-transition);
}

.filter-row input[type="text"]:focus,
.filter-row select:focus {
  outline: none;
  border-color: var(--cg-accent);
  box-shadow: 0 0 0 3px rgba(3, 105, 161, 0.12);
}

.filter-row input[type="text"]:-webkit-autofill,
.filter-row input[type="text"]:-webkit-autofill:hover,
.filter-row input[type="text"]:-webkit-autofill:focus {
  -webkit-box-shadow: 0 0 0px 1000px var(--cg-bg-surface) inset !important;
  -webkit-text-fill-color: var(--cg-text) !important;
  caret-color: var(--cg-text);
  transition: background-color 5000s ease-in-out 0s;
  border-color: var(--cg-accent);
  box-shadow: 0 0 0 3px rgba(3, 105, 161, 0.12), 0 0 0px 1000px var(--cg-bg-surface) inset !important;
}

.filter-row select[multiple] {
  height: auto;
  min-height: 70px;
}

.rating-input {
  width: 50%;
}

.checkbox-label {
  font-size: 0.8rem;
  display: flex;
  align-items: center;
  gap: 0.25rem;
  color: var(--cg-text-secondary);
  cursor: pointer;
  user-select: none;
}

.filter-actions {
  display: flex;
  justify-content: flex-end;
  gap: 0.35rem;
  margin-top: 0.25rem;
}

/* ---- Typeahead Dropdown ---- */
.typeahead-wrapper {
  position: relative;
  flex: 1;
}

.typeahead-wrapper input[type="text"] {
  width: 100%;
  box-sizing: border-box;
}

.typeahead-dropdown {
  position: absolute;
  top: 100%;
  left: 0;
  right: 0;
  z-index: 100;
  max-height: 220px;
  overflow-y: auto;
  background: var(--cg-bg-surface);
  border: 1px solid var(--cg-accent);
  border-top: 2px solid var(--cg-accent);
  border-radius: 0 0 var(--cg-radius-md) var(--cg-radius-md);
  box-shadow: var(--cg-shadow-lg);
  margin-top: -1px;
}

.typeahead-item {
  padding: 0.4rem 0.6rem;
  font-size: 0.8rem;
  font-family: var(--cg-font-body);
  color: var(--cg-text);
  cursor: pointer;
  transition: background-color var(--cg-transition);
  border-bottom: 1px solid var(--cg-border-light);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.typeahead-item:last-child {
  border-bottom: none;
}

.typeahead-item:hover,
.typeahead-item.active {
  background-color: var(--cg-primary-light);
  color: var(--cg-accent);
}

.typeahead-item.active {
  border-left: 3px solid var(--cg-primary);
  font-weight: 600;
}

.typeahead-item .match-highlight {
  color: var(--cg-accent);
  font-weight: 700;
  background-color: rgba(3, 105, 161, 0.08);
  border-radius: 2px;
  padding: 0 1px;
}

.typeahead-no-results {
  padding: 0.5rem 0.6rem;
  font-size: 0.8rem;
  color: var(--cg-text-muted);
  text-align: center;
  font-style: italic;
}

.typeahead-dropdown::-webkit-scrollbar {
  width: 5px;
}

.typeahead-dropdown::-webkit-scrollbar-track {
  background: transparent;
}

.typeahead-dropdown::-webkit-scrollbar-thumb {
  background: var(--cg-border);
  border-radius: 3px;
}

/* ---- Game List ---- */
.game-list-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 0.8rem;
  font-weight: 600;
  color: var(--cg-text-secondary);
}

.game-list {
  flex: 1;
  overflow-y: auto;
  border: 1px solid var(--cg-border);
  border-radius: var(--cg-radius-md);
  background: var(--cg-bg-surface);
}

.game-item {
  border-bottom: 1px solid var(--cg-border-light);
  font-size: 0.8rem;
  transition: background-color var(--cg-transition);
}

.game-item:last-child {
  border-bottom: none;
}

.game-item:hover {
  background-color: var(--cg-bg-hover);
}

.game-item.active {
  background-color: var(--cg-primary-light);
  border-left: 3px solid var(--cg-accent);
}

.game-item label {
  display: flex;
  align-items: center;
  padding: 0.35rem 0.5rem;
  cursor: pointer;
  width: 100%;
}

.game-item input[type="checkbox"] {
  accent-color: var(--cg-primary);
  cursor: pointer;
}

.game-info {
  flex: 1;
  margin-left: 0.5rem;
  outline: none;
}

.game-info:focus-visible {
  outline: 3px solid var(--cg-primary);
  outline-offset: -2px;
  border-radius: 2px;
}

.game-number {
  color: var(--cg-text-muted);
  margin-right: 0.25rem;
  font-size: 0.7rem;
}

.players {
  color: var(--cg-text);
  font-weight: 500;
}

.result {
  font-weight: 700;
  color: var(--cg-accent);
  font-size: 0.75rem;
}

.selection-controls {
  display: flex;
  gap: 0.25rem;
  align-items: center;
  font-size: 0.75rem;
}

.selection-count {
  margin-left: auto;
  color: var(--cg-text-muted);
}

.empty-state,
.no-games {
  padding: 2rem 1rem;
  text-align: center;
  color: var(--cg-text-muted);
  font-size: 0.85rem;
}

.filtering-indicator {
  padding: 0.35rem 0.5rem;
  font-size: 0.8rem;
  color: var(--cg-text-secondary);
  text-align: center;
  background: var(--cg-bg-alt);
  border-radius: var(--cg-radius-sm);
}

/* ---- Center Panel: Board ---- */
.board-wrapper {
  display: flex;
  flex-direction: column;
  align-items: stretch;
  gap: 0.5rem;
  width: 100%;
  max-width: calc(100vh - 350px);
}

.player-info {
  font-weight: 600;
  font-size: 1.05rem;
  color: var(--cg-text);
  width: 100%;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.player-details {
  display: flex;
  gap: 0.5rem;
  align-items: center;
}

.clock {
  font-family: var(--cg-font-mono);
  background-color: var(--cg-text);
  color: var(--cg-text-inverse);
  padding: 0.15rem 0.5rem;
  border-radius: var(--cg-radius-sm);
  font-size: 0.95rem;
  min-width: 80px;
  text-align: center;
  letter-spacing: 0.05em;
}

/* ---- Move Navigation ---- */
.move-navigation {
  display: flex;
  gap: 0.5rem;
  align-items: center;
  background: var(--cg-bg-surface);
  padding: 0.5rem 1rem;
  border-radius: var(--cg-radius-full);
  box-shadow: var(--cg-shadow-md);
}

.move-status {
  font-family: var(--cg-font-mono);
  font-weight: 600;
  font-size: 0.85rem;
  min-width: 70px;
  text-align: center;
  color: var(--cg-text);
}

/* ---- Right Panel: Moves ---- */
.move-list-section {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-height: 0;
}

.move-list-section h3,
.replay-section h3 {
  font-family: var(--cg-font-heading);
  font-size: 0.75rem;
  font-weight: 600;
  margin: 0 0 0.25rem 0;
  color: var(--cg-text);
  border-bottom: 2px solid var(--cg-accent);
  text-transform: uppercase;
  letter-spacing: 0.02em;
  padding-bottom: 0.25rem;
}

.move-list {
  flex: 1;
  overflow-y: auto;
  display: flex;
  flex-wrap: wrap;
  align-content: flex-start;
  gap: 0.25rem;
  padding: 0.35rem;
  background: var(--cg-bg-alt);
  border: 1px solid var(--cg-border);
  border-radius: var(--cg-radius-md);
}

.move-number {
  color: var(--cg-text-muted);
  font-size: 0.7rem;
  margin-left: 0.15rem;
  font-weight: 500;
}

.move-btn {
  cursor: pointer;
  padding: 2px 5px;
  border-radius: var(--cg-radius-sm);
  transition: background-color var(--cg-transition), color var(--cg-transition);
  background: none;
  border: none;
  font-family: var(--cg-font-mono);
  font-size: 0.85rem;
  color: var(--cg-text-secondary);
  text-align: left;
}

.move-btn:hover {
  background-color: var(--cg-bg-hover);
  color: var(--cg-primary);
}

.move-btn.last-move {
  background-color: var(--cg-accent);
  color: var(--cg-text-inverse);
  font-weight: 600;
}

.move-btn.active {
  background-color: var(--cg-accent);
  color: var(--cg-text-inverse);
  font-weight: 600;
}

.move-btn:focus-visible {
  outline: 3px solid var(--cg-accent);
  outline-offset: 2px;
}

/* ---- Replay Controls ---- */
.replay-section {
  margin-top: 0.5rem;
  padding-top: 0.5rem;
  border-top: 1px solid var(--cg-border-light);
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.replay-options {
  display: flex;
  gap: 0.75rem;
  font-size: 0.8rem;
}

.replay-options label {
  display: flex;
  align-items: center;
  gap: 0.25rem;
  cursor: pointer;
  color: var(--cg-text-secondary);
}

.replay-options input[type="radio"] {
  accent-color: var(--cg-accent);
}

.option-input {
  display: flex;
  align-items: center;
  gap: 0.35rem;
  font-size: 0.8rem;
  color: var(--cg-text-secondary);
}

.replay-actions {
  display: flex;
  gap: 0.35rem;
}

/* ---- PGN Input ---- */
.pgn-input-section {
  margin-top: 0.5rem;
  border-top: 1px solid var(--cg-border-light);
  padding-top: 0.5rem;
}

.pgn-input-section textarea {
  width: 100%;
  font-size: 0.75rem;
  font-family: var(--cg-font-mono);
  border: 1px solid var(--cg-border);
  border-radius: var(--cg-radius-md);
  padding: 0.5rem;
  resize: none;
  background: var(--cg-bg-alt);
  color: var(--cg-text);
  transition: border-color var(--cg-transition), box-shadow var(--cg-transition);
  box-sizing: border-box;
}

.pgn-input-section textarea:focus {
  outline: none;
  border-color: var(--cg-accent);
  box-shadow: 0 0 0 3px rgba(3, 105, 161, 0.12);
}

.pgn-input-section textarea::placeholder {
  color: var(--cg-text-muted);
}

.clipboard-buttons {
  display: flex;
  gap: 0.5rem;
  margin-top: 0.35rem;
}

/* ---- Load Section ---- */
.load-section {
  margin-top: auto;
  padding-top: 0.5rem;
  border-top: 1px solid var(--cg-border-light);
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.load-section h3 {
  font-family: var(--cg-font-heading);
  font-size: 0.75rem;
  font-weight: 600;
  margin: 0;
  color: var(--cg-text);
  text-transform: uppercase;
  letter-spacing: 0.02em;
}

.file-inputs {
  display: flex;
  gap: 0.5rem;
}

.file-input-label {
  flex: 1;
  text-align: center;
  font-size: 0.8rem;
  cursor: pointer;
  background: var(--cg-bg-alt);
  padding: 0.45rem;
  border-radius: var(--cg-radius-md);
  border: 1px dashed var(--cg-border);
  color: var(--cg-text-secondary);
  transition: background-color var(--cg-transition), border-color var(--cg-transition);
  font-weight: 500;
}

.file-input-label:hover {
  background: var(--cg-bg-hover);
  border-color: var(--cg-accent);
}

.file-input-label input {
  display: none;
}

/* ---- Lichess Date Picker ---- */
.lichess-date-picker {
  display: flex;
  flex-direction: column;
  gap: 0.35rem;
  margin-bottom: 0.5rem;
}

.lichess-date-picker > label {
  font-size: 0.8rem;
  font-weight: 600;
  color: var(--cg-text);
}

.date-selectors {
  display: flex;
  gap: 0.35rem;
  align-items: center;
}

.date-selectors select {
  padding: 0.35rem 0.5rem;
  border: 1px solid var(--cg-border);
  border-radius: var(--cg-radius-sm);
  font-size: 0.85rem;
  background: var(--cg-bg-surface);
  color: var(--cg-text);
  cursor: pointer;
  transition: border-color var(--cg-transition);
}

.date-selectors select:focus {
  outline: none;
  border-color: var(--cg-accent);
}

.date-selectors select:first-of-type {
  flex: 1;
}

.date-selectors select:nth-of-type(2) {
  width: 60px;
}

.date-selectors button {
  flex: 1;
}

.license-info {
  margin-top: 0.35rem;
  padding-top: 0.25rem;
  border-top: 1px solid var(--cg-border-light);
  text-align: center;
}

.license-info small {
  color: var(--cg-text-muted);
  font-size: 0.7rem;
}

.license-info a {
  color: var(--cg-accent);
  text-decoration: none;
}

.license-info a:hover {
  text-decoration: underline;
}

/* ---- URL Input ---- */
.url-input-section {
  display: flex;
  gap: 0.5rem;
  align-items: center;
}

.url-input {
  flex: 1;
  padding: 0.35rem 0.5rem;
  border: 1px solid var(--cg-border);
  border-radius: var(--cg-radius-sm);
  font-size: 0.8rem;
  font-family: var(--cg-font-body);
  background: var(--cg-bg-surface);
  color: var(--cg-text);
  min-width: 0;
  transition: border-color var(--cg-transition), box-shadow var(--cg-transition);
}

.url-input:focus {
  outline: none;
  border-color: var(--cg-accent);
  box-shadow: 0 0 0 3px rgba(3, 105, 161, 0.12);
}

/* ---- Buttons ---- */
button {
  cursor: pointer;
  border: none;
  border-radius: var(--cg-radius-sm);
  font-family: var(--cg-font-body);
  transition: background-color var(--cg-transition), color var(--cg-transition),
    box-shadow var(--cg-transition), transform var(--cg-transition);
  user-select: none;
}

button:focus-visible {
  outline: 3px solid var(--cg-accent);
  outline-offset: 2px;
}

button:active:not(:disabled) {
  transform: scale(0.97);
}

.primary-button {
  background: var(--cg-cta);
  color: var(--cg-text-inverse);
  padding: 0.35rem 0.85rem;
  font-size: 0.8rem;
  font-weight: 600;
  border-radius: var(--cg-radius-md);
  box-shadow: 0 2px 0 rgba(0, 0, 0, 0.1);
}

.primary-button:hover:not(:disabled) {
  background: var(--cg-cta-hover);
  box-shadow: var(--cg-shadow-sm);
}

.primary-button:disabled {
  opacity: 0.5;
  cursor: default;
  transform: none;
}

.primary-button.xsmall {
  padding: 0.15rem 0.4rem;
  font-size: 0.7rem;
}

.secondary-button {
  background: transparent;
  color: var(--cg-text-secondary);
  padding: 0.35rem 0.85rem;
  font-size: 0.8rem;
  font-weight: 500;
  border: 1px solid var(--cg-border);
  border-radius: var(--cg-radius-md);
}

.secondary-button:hover:not(:disabled) {
  background: var(--cg-bg-hover);
  color: var(--cg-text);
}

.secondary-button:disabled {
  opacity: 0.5;
  cursor: default;
  transform: none;
}

.small {
  padding: 0.25rem 0.65rem;
  font-size: 0.75rem;
}

.small-btn {
  padding: 0.25rem 0.5rem;
  font-size: 0.75rem;
  background: var(--cg-bg-alt);
  color: var(--cg-text-secondary);
  border-radius: var(--cg-radius-md);
  border: 1px solid var(--cg-border);
  font-weight: 500;
}

.small-btn:hover:not(:disabled) {
  background: var(--cg-bg-hover);
  color: var(--cg-text);
}

.icon-btn {
  padding: 0.3rem 0.5rem;
  background: transparent;
  color: var(--cg-text-secondary);
  font-size: 1rem;
  border-radius: var(--cg-radius-sm);
}

.icon-btn:hover:not(:disabled) {
  color: var(--cg-primary);
  background: var(--cg-bg-hover);
}

.icon-btn:disabled {
  opacity: 0.4;
  cursor: default;
  transform: none;
}

.nav-btn {
  background: var(--cg-bg-alt);
  color: var(--cg-text);
  width: 34px;
  height: 34px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 700;
  font-size: 0.85rem;
  transition: background-color var(--cg-transition), box-shadow var(--cg-transition),
    transform var(--cg-transition);
}

.nav-btn:hover:not(:disabled) {
  background: var(--cg-primary-light);
  color: var(--cg-accent);
  box-shadow: var(--cg-shadow-sm);
}

.nav-btn:disabled {
  opacity: 0.35;
  cursor: default;
  transform: none;
}

.action-btn {
  flex: 1;
  padding: 0.35rem 0.75rem;
  background: var(--cg-accent);
  color: var(--cg-text-inverse);
  font-size: 0.8rem;
  font-weight: 600;
  border-radius: var(--cg-radius-md);
  box-shadow: 0 2px 0 rgba(0, 0, 0, 0.1);
}

.action-btn:hover:not(:disabled) {
  background: var(--cg-accent-hover);
  box-shadow: var(--cg-shadow-sm);
}

.action-btn.stop {
  background: var(--cg-danger);
}

.action-btn.stop:hover:not(:disabled) {
  background: var(--cg-danger-hover);
}

.action-btn.full-width {
  width: 100%;
  margin-top: 0.25rem;
}

.small-input {
  width: 50px;
  padding: 0.15rem 0.35rem;
  font-size: 0.75rem;
  border: 1px solid var(--cg-border);
  border-radius: var(--cg-radius-sm);
  font-family: var(--cg-font-body);
}

/* ==========================================================================
   Board & Evaluation Bar
   ========================================================================== */

.board-container {
  display: flex;
  flex-direction: row;
  align-items: stretch;
  gap: 8px;
  width: 100%;
}

ngx-chessground {
  flex: 1;
  min-width: 0;
  min-height: 0;
  align-self: flex-start;
  aspect-ratio: 1 / 1;
  display: block;
  margin-right: 32px;
  margin-bottom: 20px;
  background: var(--cg-bg-surface);
  border-radius: var(--cg-radius-md);
  box-shadow: var(--cg-shadow-lg);
  overflow: hidden;
}

/* ng-deep overrides for chessground internals */
::ng-deep #chessground-examples {
  width: 100%;
  height: 100%;
  display: block;
}

::ng-deep #chessground-examples > section {
  width: 100%;
  height: 100%;
  display: block;
}

::ng-deep .cg-wrap {
  width: 100% !important;
  height: 100% !important;
}

::ng-deep .cg-wrap piece {
  will-change: auto !important;
}

/* ---- Evaluation Bar ---- */
.evaluation-bar-container {
  width: 22px;
  background-color: #1a1a2e;
  border-radius: var(--cg-radius-sm);
  position: relative;
  display: flex;
  flex-direction: column-reverse;
  box-shadow: inset 0 0 6px rgba(0, 0, 0, 0.4);
  margin-right: 32px;
  overflow: hidden;
}

.evaluation-fill {
  width: 100%;
  background: linear-gradient(to bottom, #f8fafc, #e2e8f0);
  transition: height 0.3s ease;
}

.evaluation-text {
  position: absolute;
  left: 100%;
  margin-left: 6px;
  font-size: 10px;
  font-weight: 700;
  color: var(--cg-text-secondary);
  pointer-events: none;
  transform: translateY(-50%);
  white-space: nowrap;
  z-index: 1;
}

/* ---- Turn Indicator ---- */
.player-name-group {
  display: flex;
  align-items: center;
  gap: 8px;
}

.turn-indicator {
  width: 12px;
  height: 12px;
  border-radius: 50%;
  display: inline-block;
  box-shadow: 0 0 3px rgba(0, 0, 0, 0.2);
  opacity: 0;
  transition: opacity var(--cg-transition);
}

.turn-indicator.active {
  opacity: 1;
}

.turn-indicator.white-turn {
  background-color: #f8fafc;
  border: 2px solid #94a3b8;
}

.turn-indicator.black-turn {
  background-color: #1e293b;
  border: 2px solid #64748B;
}

.game-result-display {
  text-align: center;
  font-weight: 700;
  color: var(--cg-cta);
  font-size: 1.15rem;
  margin-bottom: 0.25rem;
}

/* ---- Stockfish Analysis ---- */
.analysis-container {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.5rem;
  margin-bottom: 0.5rem;
  min-height: 40px;
}

.analysis-controls {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.analysis-result {
  background: var(--cg-primary-light);
  border: 1px solid var(--cg-primary);
  border-radius: var(--cg-radius-md);
  padding: 0.5rem;
  width: 100%;
  text-align: center;
  font-size: 0.85rem;
  box-sizing: border-box;
}

.analyzing-text {
  font-style: italic;
  color: var(--cg-text-secondary);
}

.best-move strong {
  color: var(--cg-primary);
  display: block;
  margin-bottom: 0.15rem;
}

.pv-line {
  font-size: 0.75rem;
  color: var(--cg-text-muted);
  word-break: break-all;
  margin-top: 4px;
}

.pv-move-btn {
  background: none;
  border: none;
  cursor: pointer;
  color: var(--cg-text-secondary);
  padding: 0 3px;
  font-size: inherit;
  font-family: var(--cg-font-body);
  border-radius: 2px;
  transition: background-color var(--cg-transition), color var(--cg-transition);
}

.pv-move-btn:hover {
  text-decoration: underline;
  color: var(--cg-accent);
  background-color: rgba(3, 105, 161, 0.08);
}

.depth-label {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-size: 0.8rem;
  color: var(--cg-text-secondary);
}

.depth-input {
  width: 55px;
  padding: 0.2rem 0.35rem;
  border: 1px solid var(--cg-border);
  border-radius: var(--cg-radius-sm);
  font-size: 0.8rem;
  transition: border-color var(--cg-transition);
}

.depth-input:focus {
  outline: none;
  border-color: var(--cg-accent);
  box-shadow: 0 0 0 3px rgba(3, 105, 161, 0.15);
}

.best-move-header {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  margin-bottom: 0.15rem;
}

.eval-score {
  font-weight: 400;
  color: var(--cg-text-secondary);
  font-size: 0.8rem;
}

/* ---- Progress Bar ---- */
.loading-indicator {
  color: var(--cg-primary);
  font-weight: 600;
  font-size: 0.85rem;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  padding: 0.6rem;
  background: var(--cg-bg-alt);
  border-radius: var(--cg-radius-md);
  border: 1px solid var(--cg-border);
}

.progress-bar-container {
  position: relative;
  width: 100%;
  height: 22px;
  background: var(--cg-bg-surface);
  border-radius: var(--cg-radius-full);
  overflow: hidden;
  box-shadow: inset 0 1px 3px rgba(3, 105, 161, 0.1);
}

.progress-bar {
  height: 100%;
  background: linear-gradient(90deg, var(--cg-accent), var(--cg-accent-hover));
  border-radius: var(--cg-radius-full);
  transition: width 0.3s ease;
  box-shadow: 0 1px 4px rgba(15, 23, 42, 0.15);
}

.progress-bar::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: linear-gradient(
    90deg,
    transparent,
    rgba(255, 255, 255, 0.25),
    transparent
  );
  background-size: 200% 100%;
  animation: shimmer 2s infinite;
}

@keyframes shimmer {
  0% {
    background-position: -200% 0;
  }
  100% {
    background-position: 200% 0;
  }
}

.progress-text {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  font-size: 0.7rem;
  font-weight: 700;
  color: var(--cg-text);
  text-shadow: 0 0 3px rgba(255, 255, 255, 0.8);
  z-index: 1;
}

.loading-status {
  font-size: 0.8rem;
  color: var(--cg-text-secondary);
  text-align: center;
}

/* ---- Scrollbars ---- */
::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: var(--cg-border);
  border-radius: 3px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--cg-text-muted);
}

/* ---- Reduced motion ---- */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }

  .progress-bar::before {
    animation: none;
  }
}

styles:
:host {
  --promo-primary: #0369A1;
  --promo-text: #0C4A6E;
  --promo-border: #d0dde6;
}

.promotion-dialog {
  padding: 0;
  min-width: 300px;
